Is there any chance that ctx->cxlrd == cxlrd? Maybe you can do:

if (ctx->cxlrd && ctx->cxlrd != cxlrd) {
	put_device(cxlrd_dev(ctx->cxlrd));
	get_device(cxlrd_dev(cxlrd));
	ctx->cxlrd = cxlrd;
}
ctx->max_hpa = max;

